@TransactionalService
class ConfigActivationService(
	private val publisher: ApplicationEventPublisher,
	private val clock: Clock,
	private val configActivationRepository: ConfigActivationRepository,
	private val configRepository: ConfigRepository,
	private val configZipFileRepository: ConfigZipFileRepository,
	private val actingUserProvider: ActingUserProvider,
	private val secretRepository: SecretRepository,
	private val keyPairRepository: KeyPairRepository,
	private val tenantRepository: TenantRepository,
) {

	@WithAuditLog(AuditAction.CONFIG_ACTIVATION_CREATE, "Created configuration activation")
	@HasConfigActivatePermissions
	@Suppress("LongMethod")
	@WithSpan
	fun activateConfig(@AuditParam tenantId: TenantId, @AuditParam configId: ConfigId): ConfigActivation {
		if (actingUserProvider.actingAdminOrClient.isActingOauthClient()) {
			tenantRepository.verifyIsNotProductionServiceLevel(tenantId)
		}

		val config = configRepository.getById(configId)
		val configZipFile = configZipFileRepository.getById(config.configZipFileId)

		val actingAdminOrClient = actingUserProvider.actingAdminOrClient
		val configActivation = ConfigActivation.create(
			tenantId,
			actingAdminOrClient.organizationId,
			ConfigActivationConfig(
				id = config.id,
				author = config.author,
				name = config.name,
				description = config.description,
				uploadDate = config.uploadDate,
				variant = config.variant,
			),
			clock.instant(),
			actingAdminOrClient.toAuthor(),
		)

		val secrets = secretRepository.findByTenantId(tenantId)
			.mapTo(mutableSetOf()) { EventSecret(it.name, it.secretRef) }

		val keyPairs = keyPairRepository.findByTenantId(tenantId)
			.mapTo(mutableSetOf()) {
				EventKeyPair(
					publicKey = it.publicKey,
					keyPairRef = it.keyPairRef,
					keyStorePath = it.keyStorePath,
					privateKeyAlias = it.privateKeyAlias,
					certificate = it.certificate,
				)
			}

		val egressTrafficPolicy = tenantRepository.getById(tenantId).egressTrafficPolicy()

		configActivationRepository.save(configActivation)
		publisher.publishEvent(
			ConfigActivatedEvent(
				configActivationId = configActivation.id,
				tenantId = tenantId,
				configId = configId,
				content = configZipFile.content,
				createdDate = clock.instant(),
				secrets = secrets,
				keyPairs = keyPairs,
				egressTrafficPolicy = egressTrafficPolicy,
			),
		)

		logger.atInfo().setMessage("Config activated")
			.addKeyValue(TENANT_ID, tenantId.value)
			.addKeyValue(CONFIG_ACTIVATION_ID, configActivation.id)
			.addKeyValue(CONFIG_ID, config.id.value)
			.addKeyValue(CONFIG_TYPE, config::class.simpleName)

		return configActivation
	}

	@WithAuditLog(AuditAction.CONFIG_ACTIVATION_UPDATE, "Updated configuration activation status")
	@HasDeploymentsManagePermissions
	@WithSpan
	fun updateConfigActivationStatus(
		@AuditParam configActivationId: ConfigActivationId,
		@AuditParam status: ConfigActivationStatus,
	) {
		val configActivation = configActivationRepository.findById(configActivationId)

		if (configActivation == null) {
			logger.atInfo()
				.setMessage("Config activation not found or marked for deletion and thus not updated")
				.addKeyValue(CONFIG_ACTIVATION_ID, configActivationId.value)
				.addKeyValue(CONFIG_ACTIVATION_STATUS, status.name).log()

			return
		}

		configActivation.status = status
		configActivation.statusUpdatedDate = clock.instant()
		configActivationRepository.save(configActivation)

		logger.atInfo()
			.setMessage("Config activation status updated")
			.addKeyValue(CONFIG_ACTIVATION_ID, configActivationId.value)
			.addKeyValue(CONFIG_ACTIVATION_STATUS, status.name).log()
	}

	@NoAuditLogRequired(reason = "Read-only operation")
	@HasConfigActivatePermissions
	@WithSpan
	fun getConfigActivationHistory(tenantId: TenantId): List<ConfigActivation> {
		tenantRepository.verifyTenantsExist(listOf(tenantId))
		return configActivationRepository.findByTenantId(tenantId)
	}

	@NoAuditLogRequired(reason = "Read-only operation")
	@HasConfigActivatePermissions
	@WithSpan
	fun getById(configActivationId: ConfigActivationId): ConfigActivation =
		configActivationRepository.getById(configActivationId)
}

private val logger = LoggerFactory.getLogger(ConfigActivationService::class.java)

