package com.airlock.saas.deployment.service.infrastructure.event

import com.airlock.saas.base.infrastructure.event.EventReceiver
import com.airlock.saas.config.service.domain.event.ConfigActivatedEvent
import com.airlock.saas.deployment.service.application.service.DeploymentConfigService
import com.airlock.saas.deployment.service.domain.model.DeploymentKeyPair
import com.airlock.saas.deployment.service.domain.model.DeploymentSecret
import com.airlock.saas.ids.DeploymentConfigId
import com.airlock.saas.ids.DeploymentId
import io.opentelemetry.instrumentation.annotations.WithSpan
import org.springframework.context.event.EventListener

@EventReceiver
class ConfigActivationEventListener(private val deploymentConfigService: DeploymentConfigService) {

	@EventListener
	@WithSpan
	fun onConfigActivated(event: ConfigActivatedEvent) {
		deploymentConfigService.createDeploymentConfig(
			DeploymentConfigId(event.configActivationId.value),
			DeploymentId(event.tenantId.value),
			event.content,
			event.secrets.map { DeploymentSecret(it.name, it.secret) },
			event.keyPairs.map {
				DeploymentKeyPair(
					it.keyPairRef,
					it.keyStorePath,
					it.privateKeyAlias,
					it.certificate,
				)
			},
			event.egressTrafficPolicy,
		)
	}
}

