package com.airlock.saas.deployment.service.application.service

import com.airlock.saas.base.application.audit.AuditAction
import com.airlock.saas.base.application.audit.AuditParam
import com.airlock.saas.base.application.audit.NoAuditLogRequired
import com.airlock.saas.base.application.audit.WithAuditLog
import com.airlock.saas.base.application.logging.DEPLOYMENT_CONFIG_ID
import com.airlock.saas.base.application.logging.DEPLOYMENT_ID
import com.airlock.saas.base.application.logging.STATUS
import com.airlock.saas.base.application.security.HasCleanupPermissions
import com.airlock.saas.base.application.security.HasDeploymentsManagePermissions
import com.airlock.saas.base.application.service.TransactionalService
import com.airlock.saas.base.domain.model.NonEmptyList
