import com.airlock.saas.ids.DeploymentId
import io.opentelemetry.instrumentation.annotations.WithSpan
import org.slf4j.LoggerFactory
import org.springframework.context.ApplicationEventPublisher
import com.airlock.saas.deployment.service.domain.event.DeploymentConfigStatus as EventDeploymentConfigStatus

@TransactionalService
class DeploymentConfigService(
	private val deploymentRepository: DeploymentRepository,
	private val deploymentConfigRepository: DeploymentConfigRepository,
	private val zipFileRepository: DeploymentConfigZipFileRepository,
	private val eventPublisher: ApplicationEventPublisher,
) {

	@HasConfigActivatePermissions
	@WithSpan
	@WithAuditLog(AuditAction.DEPLOYMENT_CONFIG_CREATE, "Created deployment configuration")
	fun createDeploymentConfig(
		@AuditParam id: DeploymentConfigId,
		@AuditParam deploymentId: DeploymentId,
		zipFile: ByteArray,
		secrets: List<DeploymentSecret>,
		keyPairs: List<DeploymentKeyPair>,
		egressTrafficPolicy: EgressTrafficPolicy,
	): DeploymentConfig {
		logger.atInfo()
			.setMessage("Creating deployment")
			.addKeyValue(DEPLOYMENT_CONFIG_ID, id)
			.addKeyValue(DEPLOYMENT_ID, deploymentId.value)
			.log()

		val deployment = deploymentRepository.getById(deploymentId)
		val deploymentConfig = DeploymentConfig(
			id = id,
			deploymentId = deployment.id,
			secrets = secrets,
			keyPairs = keyPairs,
			adminapp = AdminappModule(
				egressDestinations = NonEmptyList.createOrNull(egressTrafficPolicy.adminapp),
			),
			loginapp = LoginappModule(
				egressDestinations = NonEmptyList.createOrNull(egressTrafficPolicy.loginapp),
			),
			serviceContainer = ServiceContainerModule(
				egressDestinations = NonEmptyList.createOrNull(egressTrafficPolicy.serviceContainer),
			),
		)

		deploymentConfigRepository.save(deploymentConfig)
		zipFileRepository.save(deploymentConfig.id, deploymentId, zipFile)

		return deploymentConfig
	}

	@HasDeploymentsManagePermissions
	@WithSpan
	@NoAuditLogRequired(reason = "Read-only operation")
	fun getDeploymentConfig(id: DeploymentConfigId): DeploymentConfig = deploymentConfigRepository.getById(id)

	@HasDeploymentsManagePermissions
	@WithSpan
	@NoAuditLogRequired(reason = "Read-only operation")
	fun getDeploymentConfigZipFile(id: DeploymentConfigId): ByteArray = zipFileRepository.getContentById(id)

	@HasTenantDeletePermissions
	@WithSpan
	@WithAuditLog(AuditAction.DEPLOYMENT_CONFIG_DELETE, "Marked deployment configurations for deletion")
	fun markDeploymentConfigsForDeletion(@AuditParam deploymentId: DeploymentId) {
		deploymentConfigRepository.markForDeletionByDeploymentId(deploymentId)
		zipFileRepository.markForDeletionByDeploymentId(deploymentId)
		logger.atInfo()
			.setMessage("Deployment configs marked for deletion")
			.addKeyValue(DEPLOYMENT_ID, deploymentId.value)
			.log()
	}

	@HasCleanupPermissions
	@WithSpan
	@WithAuditLog(AuditAction.DEPLOYMENT_CONFIG_DELETE, "Deleted deployment configurations")
	fun deleteDeploymentConfigs(@AuditParam deploymentId: DeploymentId) {
		deploymentConfigRepository.deleteByDeploymentId(deploymentId)
		zipFileRepository.deleteByDeploymentId(deploymentId)
		logger.atInfo()
			.setMessage("Deployment configs deleted")
			.addKeyValue(DEPLOYMENT_ID, deploymentId.value)
			.log()
	}

	@HasDeploymentsManagePermissions
	@WithSpan
	@WithAuditLog(AuditAction.DEPLOYMENT_CONFIG_UPDATE, "Updated deployment configuration status")
	fun updateDeploymentConfigStatus(id: DeploymentConfigId, status: DeploymentConfigStatus): DeploymentConfig {
		logger.atInfo()
			.setMessage("Updating deployment config status")
			.addKeyValue(DEPLOYMENT_CONFIG_ID, id.value)
			.addKeyValue(STATUS, status)
			.log()

		val deploymentConfig = deploymentConfigRepository
			.getById(id)
			.updateStatus(status)

		persist(deploymentConfig)
		markOlderConfigsSkipped(deploymentConfig)

		return deploymentConfig
	}

	private fun markOlderConfigsSkipped(deploymentConfigUpdatedByOperator: DeploymentConfig) {
		val configs = deploymentConfigRepository.findByDeploymentIdAndStatusOrderedByCreatedDateDesc(
			deploymentId = deploymentConfigUpdatedByOperator.deploymentId,
			statuses = DeploymentConfigStatus.ONGOING_STATUSES,
			createdBefore = deploymentConfigUpdatedByOperator.createdDate,
		)

		configs
			.filter {
				/*
				 * If a config activation did not get processed by the cloud-operator at all,
				 * i.e., the status is PENDING, we can mark it as skipped directly.
				 * It won't get processed by the cloud-operator anymore.
				 *
				 * If a config activation is already being processed by the cloud-operator,
				 * i.e., the status is PROGRESSING, it can still become SUCCEEDED and the
				 * desired config activation, as this can happen when the newest config activation
				 * is failing during roll-out.
				 *
				 * When the latest config activation succeeds, we can mark all older config activations
				 * ongoing status as skipped, as they will never become a desired config activation
				 */
				it.status == DeploymentConfigStatus.PENDING ||
					(it.status.isOngoing && deploymentConfigUpdatedByOperator.status == DeploymentConfigStatus.SUCCEEDED)
			}
			.map { deploymentConfig ->
				deploymentConfig.markSkipped()
			}
			.forEach {
				persist(it)
			}
	}

	private fun persist(deploymentConfig: DeploymentConfig): DeploymentConfig {
		val savedConfig = deploymentConfigRepository.save(deploymentConfig)
		eventPublisher.publishEvent(
			DeploymentConfigUpdatedEvent(
				savedConfig.id,
				savedConfig.status.toEvent(),
			),
		)
		return savedConfig
	}

	private fun DeploymentConfigStatus.toEvent(): EventDeploymentConfigStatus =
		when (this) {
			DeploymentConfigStatus.PENDING -> EventDeploymentConfigStatus.PENDING
			DeploymentConfigStatus.PROGRESSING -> EventDeploymentConfigStatus.PROGRESSING
			DeploymentConfigStatus.SUCCEEDED -> EventDeploymentConfigStatus.SUCCESS
			DeploymentConfigStatus.CANCELLED -> EventDeploymentConfigStatus.CANCELLED
			DeploymentConfigStatus.FAILED -> EventDeploymentConfigStatus.FAILED
			DeploymentConfigStatus.SKIPPED -> EventDeploymentConfigStatus.SKIPPED
			DeploymentConfigStatus.REJECTED_INVALID_CONFIG -> EventDeploymentConfigStatus.REJECTED_INVALID_CONFIG
			DeploymentConfigStatus.REJECTED_UNSUPPORTED_VERSION -> EventDeploymentConfigStatus.REJECTED_UNSUPPORTED_VERSION
		}
}

private val logger = LoggerFactory.getLogger(DeploymentConfigService::class.java)

