// TODO ALSAAS-4266: Reconsider use of services in services
@TransactionalService
class SaasConfigService(
	private val saasConfigRepository: SaasConfigRepository,
	private val tenantRepository: TenantRepository,
	private val secretRepository: SecretRepository,
	private val transformerService: TransformerService,
	private val configService: ConfigService,
	private val configActivationService: ConfigActivationService,
	private val actingUserProvider: ActingUserProvider,
	private val clock: Clock,
	@Value("\${tenant.iam.loginapp-base-url}") private val tenantLoginappUrlPattern: String,
) {
	@NoAuditLogRequired(reason = "Read-only operation")
	@HasConfigActivatePermissions
	@WithSpan
	fun getSaasConfig(tenantId: TenantId): SaasConfig = saasConfigRepository.getByTenantId(tenantId)

	@NoAuditLogRequired(reason = "Read-only transformation operation")
	@HasConfigActivatePermissions
	@WithSpan
	fun transformSaasConfigToZip(tenantId: TenantId): ConfigZipFile {
		val tenant = tenantRepository.getById(tenantId)
		val transformedSaasConfig = transformSaasConfig(tenantId)

		return ConfigZipFile(
			tenantId = tenantId,
			organizationId = tenant.organizationId,
			content = transformedSaasConfig,
		)
	}

	@NoAuditLogRequired(reason = "Read-only transformation operation")
	@HasConfigActivatePermissions
	@WithSpan
	fun transformSaasConfig(tenantId: TenantId): ByteArray {
		val tenant = tenantRepository.getById(tenantId)
		val saasConfig = saasConfigRepository.getByTenantId(tenantId)

		val encryptionKey = secretRepository.getRequiredSecretByTenantIdAndName(tenantId, ENCRYPTION_KEY_NAME)
		val hmacKey = secretRepository.getRequiredSecretByTenantIdAndName(tenantId, HMAC_KEY_NAME)
		val loginFromNewDeviceKey =
			secretRepository.getRequiredSecretByTenantIdAndName(tenantId, LOGIN_FROM_NEW_DEVICE_KEY_NAME)

		val saasConfigZip = transformerService.transform(
			saasConfig.saasConfigData,
			ConfigSecrets(
				hmacKey = ConfigSecret(hmacKey.fileRef),
				encryptionKey = ConfigSecret(encryptionKey.fileRef),
				loginFromNewDeviceKey = ConfigSecret(loginFromNewDeviceKey.fileRef),
			),
			tenant.isProductionServiceLevel,
		)

		return saasConfigZip.toByteArray()
	}

	@WithAuditLog(AuditAction.SAAS_CONFIG_CREATE, "Added initial SaaS configuration")
	@HasTenantCreatePermissions
	@WithSpan
	fun addInitialSaasConfig(@AuditParam tenantId: TenantId): SaasConfig {
		val tenant = tenantRepository.getById(tenantId)
		val config = SaasConfig(
			tenantId = tenant.id,
			organizationId = tenant.organizationId,
			saasConfigData = SaasConfigData.initial(),
		)

		logger.atInfo()
			.setMessage("Creating Initial SaaS Config")
			.addKeyValue(TENANT_ID, tenant.id.value)
			.addKeyValue(CONFIG_ID, config.id.value)
			.log()

		return saasConfigRepository.save(config)
	}

	@WithAuditLog(AuditAction.SAAS_CONFIG_ACTIVATE, "Activated SaaS configuration")
	@HasConfigActivatePermissions
	@WithSpan
	fun activateSaasConfig(@AuditParam tenantId: TenantId): ConfigActivation {
		// TODO ALSAAS-4138: This is a shortcut that we introduced in ALSAAS-4464 to work around
		// TODO ALSAAS-4138: `createConfig`, which requires `HasConfigUploadPermission`. This should be
		// TODO ALSAAS-4138: removed or replaced.
		val config = configService.addConfigToTenant(
			tenantId = tenantId,
			configContentProvider = { transformSaasConfig(tenantId) },
			configProvider = { tenant, configZipFileId ->
				Config(
					tenantId = tenantId,
					organizationId = tenant.organizationId,
					configZipFileId = configZipFileId,
					author = actingUserProvider.actingAdminOrClient.toAuthor(),
					name = "Getting started Config",
					description = "This config was created in Getting started",
					uploadDate = clock.instant(),
				)
			},
		)

		return configActivationService.activateConfig(
			tenantId = tenantId,
			configId = config.id,
		)
	}

	@NoAuditLogRequired(reason = "Read-only operation")
	@HasConfigActivatePermissions
	@WithSpan
	fun getOidcAuthority(tenantId: TenantId): OidcAuthority =
		getSaasConfig(tenantId)
			.let {
				OidcAuthority(
					tenantLoginappUrlPattern.format(tenantId.value),
				)
			}

	@NoAuditLogRequired(reason = "Read-only verification operation")
	@HasVaultEditPermissions
	@WithSpan
	fun verifySecretNotInUse(tenantId: TenantId, secretId: SecretId) {
		saasConfigRepository.verifySecretNotInUse(tenantId, secretId)
	}
}

