import com.airlock.saas.deployment.service.infrastructure.dto.DeploymentConfigDto
import com.airlock.saas.deployment.service.infrastructure.dto.DeploymentConfigDtoMapper
import com.airlock.saas.deployment.service.infrastructure.dto.DeploymentConfigStatusDto
import com.airlock.saas.ids.DeploymentConfigId
import io.opentelemetry.instrumentation.annotations.WithSpan
import org.springframework.core.io.ByteArrayResource
import org.springframework.core.io.Resource
import org.springframework.http.HttpHeaders
import org.springframework.http.MediaType
import org.springframework.http.ResponseEntity
import org.springframework.web.bind.annotation.RestController
import java.util.*

@RestController
@IsCloudOperator
class DeploymentConfigController(
	private val deploymentConfigService: DeploymentConfigService,
	private val mapper: DeploymentConfigDtoMapper,
) : DeploymentConfigsApi {

	@WithSpan
	override fun getDeploymentConfig(deploymentConfigId: UUID): ResponseEntity<DeploymentConfigDto> {
		val deploymentConfig = deploymentConfigService.getDeploymentConfig(DeploymentConfigId(deploymentConfigId))
		val deploymentConfigDto = mapper.toDto(deploymentConfig)
		return ResponseEntity.ok(deploymentConfigDto)
	}

	@WithSpan
	override fun getDeploymentConfigZipFile(deploymentConfigId: UUID): ResponseEntity<Resource> {
		val zipFile = deploymentConfigService.getDeploymentConfigZipFile(DeploymentConfigId(deploymentConfigId))
		return ResponseEntity
			.ok()
			.contentType(MediaType("application", "zip"))
			.header(
				HttpHeaders.CONTENT_DISPOSITION,
				"attachment; filename=\"$deploymentConfigId.zip\"",
			)
			.body(ByteArrayResource(zipFile))
	}

	@WithSpan
	override fun updateDeploymentConfigStatus(
		deploymentConfigId: UUID,
