import PendingIcon from '@airlock/material-symbols/svg/outlined/pending.svg';
import PlayCircleIcon from '@airlock/material-symbols/svg/outlined/play_circle.svg';
import RocketIcon from '@airlock/material-symbols/svg/outlined/rocket.svg';
import RocketLaunchIcon from '@airlock/material-symbols/svg/outlined/rocket_launch.svg';
import React, { useEffect } from 'react';
import { useTranslation } from 'react-i18next';

import { useTranslatableMessageJSONStringTranslations } from '@airlock-cloud/management-ui/common/error.utils';
import { asTranslatableMessageJSONString } from '@airlock-cloud/management-ui/common/translatableMessage';
import useAdminHasPermission from '@airlock-cloud/management-ui/common/use-admin-has-permission/useAdminHasPermission';
import usePolledMostRecentConfigActivation from '@airlock-cloud/management-ui/common/use-config-activation/usePolledMostRecentConfigActivation';
import usePolledTenantDeployment from '@airlock-cloud/management-ui/common/use-polled-tenant-deployment/usePolledTenantDeployment';
import useSetErrorNotificationFromServerResponse from '@airlock-cloud/management-ui/common/use-set-notification/useSetErrorNotificationFromServerResponse';
import useSetNotification from '@airlock-cloud/management-ui/common/use-set-notification/useSetNotification';
import { ActionGroup } from '@airlock-cloud/management-ui/components/action-group';
import { ActionGroupItemIconColor } from '@airlock-cloud/management-ui/components/action-group/ActionGroup';
import {
	ConfigActivationStatus,
	isConfigActivationOngoing,
} from '@airlock-cloud/management-ui/domain/configActivation';
import { isDeploymentAvailable } from '@airlock-cloud/management-ui/domain/tenantDeployment';
import useActivateSaasConfig from '@airlock-cloud/management-ui/features/config-wizard/use-activate-saas-config/useActivateSaasConfig';

function DeploymentActionGroupItem({ tenantId }: DeploymentActionGroupItemProps) {
	const { t } = useTranslation();
	const { data: deployment } = usePolledTenantDeployment(tenantId);
	const polledMostRecentActivation = usePolledMostRecentConfigActivation(tenantId);
	const activateSaasConfig = useActivateSaasConfig();
	const hasConfigActivatePermission = useAdminHasPermission('config.activate');
	const submittedAtRef = React.useRef<number | null>(null);
	const setNotification = useSetNotification();
	const setErrorNotificationFromServerResponse = useSetErrorNotificationFromServerResponse();
	const translateMessageJSONString = useTranslatableMessageJSONStringTranslations();
	/**
	 * `isActivating` requires the ConfigActivation to reload, which may take a brief moment, such that it may
	 * seem to a user that the action was not submitted. To make sure the feedback appears immediately, we also
	 * use `wasSubmitted` to keep track if the action was triggered and optimistically update the action button immediately.
	 */
	const [isSubmitting, setIsSubmitting] = React.useState(false);
	const isActivating =
		isSubmitting || (!!polledMostRecentActivation && isConfigActivationOngoing(polledMostRecentActivation));

	/**
	 * Make sure to reset the submitting state again so that the components are updated according to
	 * the status of the config activation and deployment.
	 */
	useEffect(() => {
		if (isSubmitting && polledMostRecentActivation?.activationDate) {
			const activationTime = polledMostRecentActivation.activationDate.getTime();
			if (submittedAtRef.current === null || activationTime > submittedAtRef.current) {
				setIsSubmitting(false);
			}
		}
	}, [polledMostRecentActivation?.activationDate]);

	/**
	 * Order matters! We want to display the activating state as soon as the activation is submitted
	 * (and not only once the ConfigActivation update is retrieved) and thus check for this condition first.
	 */
	function getActivationState(): ActivationState {
		if (isActivating) {
			return DEPLOYMENT_STATES.Pending;
		}
		if (polledMostRecentActivation === null) {
			return DEPLOYMENT_STATES.Inactive;
		}
		if (isDeploymentAvailable(deployment)) {
			return DEPLOYMENT_STATES.Active;
		}
		// RejectedInvalidConfig and RejectedUnsupportedVersion should not occur
		// when configurations are created via the Getting Started guide
		if (
			polledMostRecentActivation.status === ConfigActivationStatus.Failed ||
			polledMostRecentActivation.status === ConfigActivationStatus.RejectedInvalidConfig ||
			polledMostRecentActivation.status === ConfigActivationStatus.RejectedUnsupportedVersion
		) {
			return DEPLOYMENT_STATES.Inactive;
		}
		return DEPLOYMENT_STATES.Unavailable;
	}

	function getActivationIcon(): {
		icon: string | number;
		color?: ActionGroupItemIconColor;
	} {
		switch (getActivationState()) {
			case DEPLOYMENT_STATES.Active:
				return { icon: RocketLaunchIcon, color: 'green' };
			case DEPLOYMENT_STATES.Inactive:
				return { icon: RocketIcon };
			case DEPLOYMENT_STATES.Pending:
				return { icon: PendingIcon, color: 'blue' };
			case DEPLOYMENT_STATES.Unavailable:
				return { icon: PendingIcon, color: 'yellow' };
		}
	}

	function getActivationTitle() {
		switch (getActivationState()) {
			case DEPLOYMENT_STATES.Active:
				return t('features.configuration.wizard.operation.deployment.title.success', {
					defaultValue: 'Active',
				});
			case DEPLOYMENT_STATES.Inactive:
				return t('features.configuration.wizard.operation.deployment.title.inactive', {
					defaultValue: 'Inactive',
				});
			case DEPLOYMENT_STATES.Pending:
				return t('features.configuration.wizard.operation.deployment.title.pending', {
					defaultValue: 'Activation in progress..',
				});
			case DEPLOYMENT_STATES.Unavailable:
				return t('features.configuration.wizard.operation.deployment.title.unavailable', {
					defaultValue: 'Tenant unavailable',
				});
		}
	}

	function getActivationSubtitle() {
		switch (getActivationState()) {
			case DEPLOYMENT_STATES.Active:
				return t('features.configuration.wizard.operation.deployment.subtitle.success', {
					defaultValue: 'Your tenant is ready',
				});
			case DEPLOYMENT_STATES.Inactive:
				return t('features.configuration.wizard.operation.deployment.subtitle.inactive', {
					defaultValue: 'Activate tenant to enable login and user management',
				});
			case DEPLOYMENT_STATES.Pending:
				return t('features.configuration.wizard.operation.deployment.subtitle.pending', {
					defaultValue: 'This may take a few minutes',
				});
			case DEPLOYMENT_STATES.Unavailable:
				return t('features.configuration.wizard.operation.deployment.subtitle.unavailable', {
					defaultValue: 'Tenant cannot currently be reached',
				});
		}
	}

	const handleSubmit = async () => {
		submittedAtRef.current = Date.now();
		setIsSubmitting(true);
		await activateSaasConfig(tenantId, {
			onError: (error) => {
				setIsSubmitting(false);
				// TODO ALSAAS-4330: this is a code duplicate from src/form/Form.tsx
				// TODO ALSAAS-4330: this should be moved into one of the error notification handlers.
				if (error.status && error.status !== 400) {
					setErrorNotificationFromServerResponse(error);
				} else if (error.error) {
					const translatableMessage = asTranslatableMessageJSONString(
						error.error.code,
						error.error.meta?.parameters
					);
					setNotification({
						level: 'error',
						message: translateMessageJSONString(translatableMessage),
					});
				}
			},
		});
	};

	return (
		<ActionGroup.Item
			icon={getActivationIcon()}
			title={getActivationTitle()}
			subtitle={getActivationSubtitle()}
			actionButton={{
				label: t('features.configuration.wizard.operation.deployment.button.label', {
					defaultValue: 'Activate tenant',
				}),
				icon: PlayCircleIcon,
				action: handleSubmit,
				loading: isActivating,
			}}
			// TODO ALSAAS-4138: Use appropriate permission here
			disabled={!hasConfigActivatePermission}
		/>
	);
}

type DeploymentActionGroupItemProps = {
	tenantId: string;
};

const DEPLOYMENT_STATES = {
	Inactive: 'inactive',
	Pending: 'pending',
	Active: 'active',
	Unavailable: 'unavailable',
} as const;

type ActivationState = (typeof DEPLOYMENT_STATES)[keyof typeof DEPLOYMENT_STATES];

export default DeploymentActionGroupItem;

