import { deserializeConfig } from '@airlock-cloud/management-ui/api/configs/configs.api';
import { Tenant, TenantCreateRequest, TenantUpdate } from '@airlock-cloud/management-ui/domain/tenant';
import { TenantAuthorizedAdminappUrl } from '@airlock-cloud/management-ui/domain/tenantAuthorizedAdminappUrl';
import { TenantDeployment } from '@airlock-cloud/management-ui/domain/tenantDeployment';
import {
	TenantDeploymentUserCreateRequest,
	TenantDeploymentUserCreateResponse,
} from '@airlock-cloud/management-ui/domain/tenantDeploymentUser';

import { mapDomainToRequestDto, validateAndMapResponseDtoToDomain } from '../jsonapi';

class TenantsApi {
	api: Api;
	type: TypeDto = TypeDto.Tenant;

	constructor(baseConfig: Configuration, axiosInstance: AxiosInstance) {
		this.api = new Api(baseConfig, undefined, axiosInstance);
	}

	async createTenant(tenant: TenantCreateRequest, options?: AxiosRequestConfig): Promise<Tenant> {
		return this.api.createTenant(mapDomainToRequestDto(tenant, this.type), options).then((res) => {
			return validateAndMapResponseDtoToDomain(res.data);
		});
	}

	async createUserInDeployment(
		tenantId: string,
		request: TenantDeploymentUserCreateRequest,
		options?: AxiosRequestConfig
	): Promise<TenantDeploymentUserCreateResponse> {
		return this.api
			.createUserInDeployment(tenantId, mapDomainToRequestDto(request, TypeDto.DeploymentUser), options)
			.then((res) => {
				return validateAndMapResponseDtoToDomain(res.data);
			});
	}

	async deleteTenant(tenantId: string, options?: AxiosRequestConfig): Promise<unknown> {
		return this.api.deleteTenant(tenantId, options);
	}

	async findTenant(tenantId: string, options?: AxiosRequestConfig): Promise<Tenant> {
		return this.api.findTenant(tenantId, options).then((res) => validateAndMapResponseDtoToDomain(res.data));
	}

	async getTenants(options?: AxiosRequestConfig): Promise<Tenant[]> {
		return this.api.getTenants(options).then((res) => validateAndMapResponseDtoToDomain(res.data));
	}

	async findTenantDeployment(tenantId: string, options?: AxiosRequestConfig): Promise<TenantDeployment> {
		return this.api
			.findTenantDeployment(tenantId, options)
			.then((res) => validateAndMapResponseDtoToDomain(res.data, deserializeTenantDeployment));
	}

	async updateTenant(tenantId: string, tenant: TenantUpdate, options?: AxiosRequestConfig): Promise<Tenant> {
		return this.api
			.updateTenant(tenantId, mapDomainToRequestDto(tenant, this.type), options)
			.then((res) => validateAndMapResponseDtoToDomain(res.data));
	}

	async getTenantAuthorizedAdminappUrl(
		tenantId: string,
		options?: AxiosRequestConfig
	): Promise<TenantAuthorizedAdminappUrl> {
		return this.api
			.getAuthorizedAdminappUrl(tenantId, options)
			.then((res) => validateAndMapResponseDtoToDomain(res.data));
	}

	async getTenantAuthorizedAdminappUrlByAdminappUrl(
		adminAppUrl: string,
		options?: AxiosRequestConfig
	): Promise<TenantAuthorizedAdminappUrl> {
		return this.api
			.getAuthorizedAdminappUrlByAdminappUrl(adminAppUrl, options)
			.then((res) => validateAndMapResponseDtoToDomain(res.data));
	}

	async getTenantAdminappUrls(options?: AxiosRequestConfig): Promise<string[]> {
		return this.api
			.getTenantAdminappUrls(options)
			.then((res) =>
				validateAndMapResponseDtoToDomain<TenantAdminappUrlAttributesDto, TenantAuthorizedAdminappUrl>(res.data)
			)
			.then((list) => list.map((item) => item.url));
	}
}

function deserializeTenantDeployment(attributesDto: TenantDeploymentAttributesDto): TenantDeployment {
	if (!attributesDto.config) {
		return {};
	}
	return { config: deserializeConfig(attributesDto.config) };
}

export default TenantsApi;

